module top_module(
  input [n-1:0] in,
  output [m-1:0] out
);parameter n = 3; // number of input signals
parameter m = 8; // number of output signals

reg [m-1:0] invalid_out;

always @(*) begin
  case(in)
    3'b000: invalid_out = 8'b00000001;
    3'b001: invalid_out = 8'b00000010;
    3'b010: invalid_out = 8'b00000100;
    3'b011: invalid_out = 8'b00001000;
    3'b100: invalid_out = 8'b00010000;
    3'b101: invalid_out = 8'b00100000;
    3'b110: invalid_out = 8'b01000000;
    3'b111: invalid_out = 8'b10000000;
    default: invalid_out = 8'b00000000;
  endcase
end

assign out = invalid_out;

endmodule
